INSERT INTO simulados (id, title, slug, sequence_number, description, questions_count, duration_minutes, execution_window_start, execution_window_end, results_release_at, theme_tags, status)
INSERT INTO questions (id, simulado_id, question_number, text, area, theme, difficulty, explanation) VALUES
('50100001-0001-4001-8001-000000000001', 'a5a5a5a5-5555-5555-5555-555555555555', 1, 'Paciente de 58 anos, hipertenso e diabético, apresenta dor torácica retroesternal em aperto há 40 minutos, irradiando para MSE, com sudorese e náuseas. ECG mostra supradesnivelamento de ST em DII, DIII e aVF. Qual a conduta inicial mais adequada?', 'Clínica Médica', 'Cardiologia', 'medium', 'IAM inferior com supra de ST exige reperfusão imediata. A angioplastia primária é o tratamento de escolha quando disponível em até 90 minutos.'),
('50100001-0001-4001-8001-000000000002', 'a5a5a5a5-5555-5555-5555-555555555555', 2, 'Mulher de 32 anos apresenta poliúria, polidipsia e perda ponderal de 8 kg em 2 meses. Glicemia de jejum: 280 mg/dL. Qual o diagnóstico mais provável?', 'Clínica Médica', 'Endocrinologia', 'easy', 'Quadro clássico de DM tipo 1 com início em adulto jovem.'),
('50100001-0001-4001-8001-000000000003', 'a5a5a5a5-5555-5555-5555-555555555555', 3, 'Homem de 45 anos, etilista crônico, apresenta ascite volumosa, icterícia e eritema palmar. Qual exame é mais importante para avaliar a função hepática sintética?', 'Clínica Médica', 'Gastroenterologia', 'medium', 'O tempo de protrombina (INR) reflete a capacidade de síntese hepática de fatores de coagulação.'),
('50100001-0001-4001-8001-000000000004', 'a5a5a5a5-5555-5555-5555-555555555555', 4, 'Criança de 4 anos com edema periorbital matinal, urina espumosa e hipoalbuminemia (1,8 g/dL). Proteinúria de 24h: 3,8 g. Qual o diagnóstico mais provável?', 'Clínica Médica', 'Nefrologia', 'medium', 'Síndrome nefrótica em crianças de 2-6 anos é mais comumente causada por doença por lesões mínimas.'),
('50100001-0001-4001-8001-000000000005', 'a5a5a5a5-5555-5555-5555-555555555555', 5, 'Paciente de 70 anos com DPOC grave apresenta dispneia progressiva, cianose central e PaCO2 de 58 mmHg. Qual a conduta ventilatória mais indicada?', 'Clínica Médica', 'Pneumologia', 'hard', 'VNI com BiPAP é primeira linha em DPOC exacerbado com hipercapnia.'),
('50100001-0001-4001-8001-000000000006', 'a5a5a5a5-5555-5555-5555-555555555555', 6, 'Homem de 28 anos, ferimento por arma branca em hipocôndrio esquerdo, instável (PA: 70x40, FC: 130). Qual a conduta imediata?', 'Cirurgia', 'Trauma', 'medium', 'Paciente instável com trauma penetrante abdominal tem indicação de laparotomia exploradora imediata.'),
('50100001-0001-4001-8001-000000000007', 'a5a5a5a5-5555-5555-5555-555555555555', 7, 'Mulher de 35 anos com dor em FID há 12h, febre de 38,2°C e sinal de Blumberg positivo. Leucócitos: 14.000. Qual o diagnóstico mais provável?', 'Cirurgia', 'Abdome Agudo', 'easy', 'Quadro clássico de apendicite aguda.'),
('50100001-0001-4001-8001-000000000008', 'a5a5a5a5-5555-5555-5555-555555555555', 8, 'Paciente de 62 anos com hérnia inguinal irredutível há 6 horas, dor intensa, vômitos e distensão abdominal. Qual a classificação dessa hérnia?', 'Cirurgia', 'Hérnias', 'medium', 'Hérnia irredutível com sinais de obstrução configura hérnia encarcerada.'),
('50100001-0001-4001-8001-000000000009', 'a5a5a5a5-5555-5555-5555-555555555555', 9, 'Homem de 50 anos com queimadura de 2º grau profundo em 30% da SCQ. Pela fórmula de Parkland, qual o volume de RL nas primeiras 24h para 80 kg?', 'Cirurgia', 'Queimaduras', 'hard', 'Fórmula de Parkland: 4 mL x 80 x 30 = 9.600 mL.'),
('50100001-0001-4001-8001-000000000010', 'a5a5a5a5-5555-5555-5555-555555555555', 10, 'Paciente de 55 anos com nódulo tireoidiano de 3 cm, sólido, hipoecogênico, com microcalcificações ao US. TSH normal. Qual o próximo passo?', 'Cirurgia', 'Cirurgia de Cabeça e Pescoço', 'medium', 'Nódulo suspeito deve ser avaliado com PAAF guiada por US.');
